import { useState } from "react";

const API = "http://127.0.0.1:8000";

function BMI({ token, onLogout }) {
  const [form, setForm] = useState({ age: "", weight: "", height: "" });
  const [result, setResult] = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");

  const handleChange = (e) => {
    setForm({ ...form, [e.target.name]: e.target.value });
  };

  const handleCalculate = async () => {
    setLoading(true);
    setError("");
    setResult(null);
    try {
      const res = await fetch(`${API}/bmi`, {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          Authorization: `Bearer ${token}`,
        },
        body: JSON.stringify({
          age: parseInt(form.age),
          weight: parseFloat(form.weight),
          height: parseFloat(form.height),
        }),
      });
      const data = await res.json();
      if (res.ok) {
        setResult(data);
      } else {
        setError("❌ " + data.detail);
      }
    } catch {
      setError("❌ Server error");
    }
    setLoading(false);
  };

  const getCategoryColor = (category) => {
    if (category === "Underweight") return "#60a5fa";
    if (category === "Normal weight") return "#4ade80";
    if (category === "Overweight") return "#facc15";
    return "#f87171";
  };

  return (
    <div style={styles.card}>
      <div style={styles.header}>
        <h1 style={styles.title}>🧮 BMI Calculator</h1>
        <button style={styles.logout} onClick={onLogout}>Logout</button>
      </div>

      <div style={styles.form}>
        <input
          style={styles.input}
          type="number"
          name="age"
          placeholder="Age (years)"
          value={form.age}
          onChange={handleChange}
        />
        <input
          style={styles.input}
          type="number"
          name="weight"
          placeholder="Weight (kg)"
          value={form.weight}
          onChange={handleChange}
        />
        <input
          style={styles.input}
          type="number"
          name="height"
          placeholder="Height (cm)"
          value={form.height}
          onChange={handleChange}
        />

        {error && <p style={styles.error}>{error}</p>}

        <button style={styles.button} onClick={handleCalculate} disabled={loading}>
          {loading ? "Calculating..." : "Calculate BMI"}
        </button>
      </div>

      {result && (
        <div style={styles.result}>
          <p style={styles.bmiValue}>{result.bmi}</p>
          <p style={{ ...styles.category, color: getCategoryColor(result.category) }}>
            {result.category}
          </p>
          <p style={styles.info}>Age: {result.age} years</p>
        </div>
      )}
    </div>
  );
}

const styles = {
  card: {
    background: "#1a1a1a",
    padding: "40px",
    borderRadius: "16px",
    width: "100%",
    maxWidth: "420px",
    boxShadow: "0 0 30px rgba(0,0,0,0.5)",
  },
  header: {
    display: "flex",
    justifyContent: "space-between",
    alignItems: "center",
    marginBottom: "24px",
  },
  title: {
    fontSize: "22px",
    color: "#4ade80",
  },
  logout: {
    background: "transparent",
    border: "1px solid #444",
    color: "#aaa",
    padding: "6px 12px",
    borderRadius: "6px",
    fontSize: "13px",
  },
  form: {
    display: "flex",
    flexDirection: "column",
    gap: "14px",
  },
  input: {
    padding: "12px",
    borderRadius: "8px",
    border: "1px solid #333",
    background: "#0f0f0f",
    color: "#fff",
    fontSize: "15px",
  },
  button: {
    padding: "12px",
    borderRadius: "8px",
    background: "#4ade80",
    color: "#000",
    fontWeight: "bold",
    fontSize: "16px",
    border: "none",
  },
  result: {
    marginTop: "28px",
    textAlign: "center",
    padding: "20px",
    background: "#0f0f0f",
    borderRadius: "12px",
    border: "1px solid #333",
  },
  bmiValue: {
    fontSize: "52px",
    fontWeight: "bold",
    color: "#fff",
  },
  category: {
    fontSize: "20px",
    fontWeight: "bold",
    marginTop: "8px",
  },
  info: {
    marginTop: "8px",
    color: "#888",
    fontSize: "14px",
  },
  error: {
    color: "#f87171",
    fontSize: "14px",
    textAlign: "center",
  },
};

export default BMI;
